func TestGateway_GraphQLResponseFormat_Success(t *testing.T) {
	mock := newMockNATSRequester()

	// Return raw data from coordinator
	coordinatorResponse := []byte(`{"entities":[{"id":"test.entity.001","triples":[]}]}`)
	mock.requestFunc = func(ctx context.Context, subject string, data []byte, timeout time.Duration) ([]byte, error) {
		return coordinatorResponse, nil
	}

	comp := createTestGatewayWithMock(t, mock)
	require.NoError(t, comp.Initialize())
	require.NoError(t, comp.Start(context.Background()))
	defer comp.Stop(5 * time.Second)

	gqlRequest := map[string]interface{}{
		"query": `query { pathSearch(startEntity: "test.entity.001", maxDepth: 3) { entities } }`,
	}
	body, err := json.Marshal(gqlRequest)
	require.NoError(t, err)

	req := httptest.NewRequest(http.MethodPost, "/graphql", bytes.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()

	comp.handleGraphQL(w, req)

	assert.Equal(t, http.StatusOK, w.Code)
	assert.Equal(t, "application/json", w.Header().Get("Content-Type"))

	// Verify response is wrapped in GraphQL format: {"data": {"pathSearch": {...}}}
	var response map[string]interface{}
	err = json.Unmarshal(w.Body.Bytes(), &response)
	require.NoError(t, err)

	data, ok := response["data"].(map[string]interface{})
	assert.True(t, ok, "response should have 'data' field")
	assert.NotNil(t, data)

	// Verify data contains pathSearch field with coordinator response
	pathSearch, ok := data["pathSearch"]
	assert.True(t, ok, "data should have 'pathSearch' field")
	assert.NotNil(t, pathSearch)

	// Verify pathSearch contains coordinator response
	pathSearchJSON, err := json.Marshal(pathSearch)
	require.NoError(t, err)
	assert.JSONEq(t, string(coordinatorResponse), string(pathSearchJSON), "pathSearch should match coordinator response")
}

