func TestGateway_HTTPMethodValidation(t *testing.T) {
	comp := createTestGateway(t)
	require.NoError(t, comp.Initialize())
	require.NoError(t, comp.Start(context.Background()))
	defer comp.Stop(5 * time.Second)

	tests := []struct {
		name           string
		method         string
		expectedStatus int
	}{
		{
			name:           "POST allowed",
			method:         http.MethodPost,
			expectedStatus: http.StatusBadRequest, // Bad request due to invalid body, but method is accepted
		},
		{
			name:           "GET not allowed for mutations",
			method:         http.MethodGet,
			expectedStatus: http.StatusMethodNotAllowed,
		},
		{
			name:           "PUT not allowed",
			method:         http.MethodPut,
			expectedStatus: http.StatusMethodNotAllowed,
		},
		{
			name:           "DELETE not allowed",
			method:         http.MethodDelete,
			expectedStatus: http.StatusMethodNotAllowed,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			var bodyReader io.Reader
			if tt.method == http.MethodPost {
				bodyReader = bytes.NewReader([]byte(`{invalid}`)) // Invalid to trigger 400
			}

			req := httptest.NewRequest(tt.method, "/graphql", bodyReader)
			if tt.method == http.MethodPost {
				req.Header.Set("Content-Type", "application/json")
			}
			w := httptest.NewRecorder()

			comp.handleGraphQL(w, req)

			assert.Equal(t, tt.expectedStatus, w.Code)
		})
	}
}

