// createTestGateway creates a basic test gateway with mock NATS client
func createTestGateway(t *testing.T) *Component {
	t.Helper()

	mock := newMockNATSRequester()
	return createTestGatewayWithMock(t, mock)
}

// createTestGatewayWithMock creates a test gateway with provided mock client
func createTestGatewayWithMock(t *testing.T, mock *mockNATSRequester) *Component {
	t.Helper()

	config := DefaultConfig()

	// Create component with injected mock
	// Note: Builder must implement a way to inject mock for testing
	// Following the pattern from graph-query tests
	comp := &Component{
		name:          "graph-gateway",
		config:        config,
		natsRequester: mock, // Builder will add this field for NATS request/reply
		logger:        createTestLogger(),
	}

	comp.lastActivity.Store(time.Now())

	return comp
}

// createTestLogger creates a logger for testing
func createTestLogger() *slog.Logger {
	return slog.Default()
}
